import java.util.Scanner;

public class SafeBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Perform input validation to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input length exceeds buffer size. Please enter a shorter name.");
            return;
        }

        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), buffer.length), buffer, 0);

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any extra spaces

        // Alternatively, you can use a StringBuilder to avoid fixed-size buffers
